var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"최악의 상황을 생각해서 최정예 구조팀을 꾸리고 있었는데…","JPN":"最悪の状況を想定して最精鋭の救助チームを作ってたけど……","ENG":"I was assembling an elite rescue team in anticipation of the worst-case scenario...","TWN":"考慮到最壞的情況，我正在組織最精銳的救援隊……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L3_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나한테 연락한 걸 보면 무사히 도착한 모양이네.","JPN":"私に連絡できたんだから、無事到着したようだね。","ENG":"But seeing how you called me, I guess you arrived safely.","TWN":"不過看到你聯絡我，就表示是平安到達了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"다행이군. 연구에 몰두하느라 연락을 못 받으면 어쩌나 했는데 말이지.","JPN":"研究に夢中で連絡が取れなかったらどうしようかと思っていたが、そうでなくてよかった。","ENG":"That's a relief. I was worried you might not pick up being too focused on working.","TWN":"太好了。我還擔心你太專注於研究而收不到呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"흥, 난 일곱 가지 일을 동시에 할 수 있는 천재라고.","JPN":"フン、私は7つの仕事を同時にこなせる天才なんだよ。","ENG":"Hmph! I'm a genius who can multitask seven things at once.","TWN":"呃，我可是能同時做七件事的天才。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이렇게 연락을 받으면서도 내 작업은 진전을 이루는 중이니 걱정 마.","JPN":"こうやって連絡してる間にも私の作業は進展中だから心配しないで。","ENG":"I'm making progress with my work even while talking to you like this, so don't worry.","TWN":"即使在與你們通訊的同時，我的工作也在取得進展，所以不用擔心。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"일곱 가지 일을 동시에…?","JPN":"7つの仕事を同時に……？","ENG":"Seven things simultaneously...?","TWN":"同時做七件事……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"시니어님은 동시사고 능력을 가진 카운터입니다.","JPN":"シニア様は同時思考能力を持つカウンターです。","ENG":"Senior Isolde is a Counter with an ability to multi-thinking.","TWN":"前輩是擁有一心多用能力的制裁者。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"가끔 통제를 잃고 굉장히 소심하거나 험악해지는 것만 아니면, 유용한 능력이죠.","JPN":"たまに統制を失って気が弱くなったり、険悪になったりすることを除けば、役に立つ能力です。","ENG":"It's a useful ability, despite the fact that she might lose control and become extremely timid or aggressive.","TWN":"只要不偶爾失控變得過於膽怯或者過於暴躁，這還是個非常有用的能力。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그거 혹시… 여러 사람의 인격이 들어있는 건가요?","JPN":"それ、もしかして……色んな人の人格が入ってるんですか？","ENG":"Then... does she have multiple personalities inside of her?","TWN":"意思是……她有好幾種人格嗎……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"잡담은 됐고, 용건이나 말해.","JPN":"無駄話はいいから、用件だけ話してよ。","ENG":"Let's cut the chit-chat and get to the point.","TWN":"閒聊到此為止，讓我們進入正題吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"지금 어디야?","JPN":"今どこなの？","ENG":"Where are you right now?","TWN":"你們現在到哪了？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우린 지금 그라운드 제로의 목적지에 도착했네.","JPN":"私たちは今、グラウンド・ゼロの目的地に到着した。","ENG":"We've arrived at our destination, Ground Zero.","TWN":"我們已經到達目的地了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"<color=#ffd34c>우물</color>이라고 불리는, 아주 작은 크기의 차원 터널 앞에 있지.","JPN":"<color=#ffd34c>井戸</color>と呼ばれている、とても小さな次元トンネルの前にいる。","ENG":"We're right in front of a miniature dimension tunnel that they call the <color=#ffd34c>Well</color>.","TWN":"正站在稱為<color=#ffd34c>井</color>的極狹窄次元隧道前面。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"잠깐… 뭐? 이제 막 국경을 넘은 게 아니라 벌써 목적지에 도착했다고?!","JPN":"ちょっと……は？　国境を越えたんじゃなくて、もう目的地に着いたの！？","ENG":"Wait... What? You didn't just cross the border, but you're already there?!","TWN":"等一下……什麼？我以為剛剛越過國境呢，你們已經到達目的地了？!"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"균열을 둘러싼 밸브의 보안시스템을 내 도움도 없이 뚫었단 말이야?","JPN":"亀裂を囲んでいるバルブの保安システムを、私の助けなしで突破したってこと？","ENG":"You're telling me that you bypassed the Valve's security surrounding the Crevice without my help?","TWN":"竟然在沒有我説明的情況下破解了圍繞峽谷的閥門安全系統？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"말씀하신 밸브의 관문은 저희가 갔을 때 운석에 맞은 것처럼 망가져 있었습니다.","JPN":"そのバルブの関門は、私たちが着いた時には隕石が衝突したように破壊されていました。","ENG":"The Valve gate you mentioned was damaged as if it had been hit by a meteorite.","TWN":"你提到的閥門關口在我們到達時已經像被隕石擊中一樣損壞了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그와는 별개로, 상부 지시를 받은 군인이 저희를 안내해주더군요.","JPN":"それとは別に、上層部から指示を受けた軍人が私たちを案内してくれたんです。","ENG":"Separately from that, soldiers with orders from their superiors escorted us here.","TWN":"除此之外，是接到了北方和議會上級指示的士兵帶我們來到了這裡。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"참모총장의 지시라는 이유만으로 신원확인 절차 없이 밸브를 통과했습니다.","JPN":"総参謀長の指示という理由だけで、身元を確認することなくバルブを通れたのです。","ENG":"So, we were able to pass the Valve without any identification procedures simply because it was an order from the Chief of the General Staff.","TWN":"因此，單憑參謀總長的指示，我們沒有經過身份驗證程序就通過了閥門。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"뭐야 그게…? 무슨 함정 같은 건가?","JPN":"何それ……？　何かの罠？","ENG":"What the...? Could it be some kind of trap?","TWN":"那是什麼……？是陷阱嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"함정이라해도 목적지에 무사히 도착했단 사실은 변함없네.","JPN":"罠だとしても目的地に無事到着した事実に変わりはない。","ENG":"Even if it is, it doesn't change the fact that we arrived safely at our destination.","TWN":"即使是陷阱，總之是順利到達目的地了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"계획을 차질 없이 진행할 수 있다는 뜻이지.","JPN":"支障なく計画を進行できるという意味さ。","ENG":"This means that we can proceed with our plan without any issues.","TWN":"這就表示計畫進行順利。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…알겠어. 원격 모듈을 조정할 테니 2분 30초 기다려.","JPN":"……わかった。遠隔モジュールを調整するから、2分30秒待ってて。","ENG":"...All right. I'll adjust the remote module, so give me 2 minutes and 30 seconds.","TWN":"……知道了。我調整下遠端模組，我需要2分30秒。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"분석 결과. 그 <color=#ffd34c>우물</color>이라는 장소에서 다이브를 시도한 흔적을 발견했어.","JPN":"分析結果。あの<color=#ffd34c>井戸</color>って場所からダイブしようとして痕跡を発見した。","ENG":"From the result of my analysis, I found traces of dive attempts at this <color=#ffd34c>Well</color> place.","TWN":"分析結果顯示，在<color=#ffd34c>井</color>的周圍有嘗試躍入的痕跡。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이 흔적은 당신 말처럼 관리국에 등록된 죄수 패러독스의 고유 CRF파형과 일치해.","JPN":"この痕跡はあなたの言うとおり、管理局に登録された囚人パラドックスの固有CRFの波形と一致してる。","ENG":"These traces, as you said, match the unique CRF wavelengths of a prisoner named Paradox registered with the Administration.","TWN":"這個痕跡和你說的一樣，與管理局登記的罪犯悖論的專屬CRF波形一致。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무사히 다이브에 성공한 거라면, 갑자기 연락이 끊긴 이유도 설명이 되는군.","JPN":"無事ダイブに成功したのなら、急に連絡が途絶えた理由も説明がつくな。","ENG":"So if the dive was successful, it could explain why we couldn't suddenly reach her.","TWN":"嗯，如果是成功躍入的話，突然失聯的原因也就解釋得通了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"통보도 없이 사라져서 걱정했는데, 기우였던 모양이야.","JPN":"通報もなく消えて心配したんだが、杞憂だったようだ。","ENG":"I was worried because she disappeared without notice, but it seems my worries were for naught.","TWN":"她沒先說一聲就消失了，我還擔心了一下，看來是我多慮了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그럼 한 건 해결이네.","JPN":"じゃあ、一件落着だね。","ENG":"That solves one thing.","TWN":"那這件事就解決了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"이제 다른 한 명만 더 찾으면 되는 거지?","JPN":"あとはもう1人探せばいいんだっけ？","ENG":"So, we have one more person to find, right?","TWN":"現在只要再找一個人就行了吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래. 지금부터는 잭슨의 행방을 알아봐야겠지.","JPN":"ああ。今からジャクソンの行方を探してみる。","ENG":"Yes. We'll search for Jackson's whereabouts now.","TWN":"沒錯。現在該查查傑森的下落了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그 전에 묻고 싶은 게 있는데. 당신 직원은 왜 이런 곳까지 온 거야?","JPN":"その前に聞きたいんだけど。あなたの職員はなんでこんなところまで来たんだ？","ENG":"There was something I've been meaning to ask. Why would one of your employees even go over there?","TWN":"在那之前我有個問題。你的員工為什麼會來這種地方？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"내 직원이 감사 기간에 해외로 간 걸 문제 삼는 거라면, 나중에 해명하지.","JPN":"私の職員が監査の期間中に海外へ行ったことを言及しているのなら、後で釈明しよう。","ENG":"If you are making an issue of one of my employees being overseas during the audit period, I'll explain it later.","TWN":"如果你對我的員工在監查期間出國有意見的話，之後我會解釋的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그렇게 생각했다면 실례네. 난 말루프 아줌마처럼 꽉 막힌 인간이 아니거든?","JPN":"そう思ったなら失礼だね。私はマルーフのおばさんみたいに生真面目じゃないんだよ。","ENG":"I'm almost offended you thought that way. I'm not a stuck-up like Maalouf, you know.","TWN":"你也太看不起我了？我可不是像瑪盧夫阿姨那樣頑固的人？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"내가 묻고 싶은 건, 왜 굳이 다이브를 위해 그라운드 제로까지 왔어야 했냐는 거야.","JPN":"私が聞きたいのは、ダイブをするためにグラウンド・ゼロまで来る必要があったのかってこと。","ENG":"What I'm asking is, why did she go all the way to Ground Zero to dive.","TWN":"我想問的是，為什麼非得為了躍入來到G0那個地方。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"균열을 고작 고심도로 가는 지름길로 쓰려고 북방합의체의 경비를 시험한다는 건 굉장히 무모하고 비효율적인 짓이라고.","JPN":"高深度への近道に亀裂を使うために北方合意体の警備を試すって、まったく無茶で非効率的なマネじゃない。","ENG":"It seems extremely reckless and inefficient to test the Northern Union's security just to use the Crevice as a shortcut to the hyperdepths.","TWN":"想要把峽谷當作通往深層的捷徑入口，而因此衝擊北方和議會的防線，這實在是非常魯莽且沒效率的行為。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"차원함선이 공간의 축을 수정해 이면세계로 간다면…","JPN":"次元艦船が空間の軸を修正して裏世界に行くのなら……","ENG":"Dimensional ships modify the axis of space to enter the Counterside...","TWN":"嗯，如果說次元艦船是透過修正空間軸而進入異界的話……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"우리 직원에겐 시간의 축을 움직여 이면세계로 가는 <color=#ffd34c>특별한 수단</color>이 있기 때문이지.","JPN":"私の職員には時間の軸を動かして裏世界に行く<color=#ffd34c>特別な手段</color>があるからさ。","ENG":"And my employee has a <color=#ffd34c>special means</color> of going to the Counterside by moving the axis of time.","TWN":"那我的員工便是可以透過某種<color=#ffd34c>特殊的手段</color>，移動時間軸來前往異界。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 공간과 시간, 두 개의 축을 동시에 조작할 수는 없기 때문에 반드시 정해진 장소로 가야만 했던 걸세.","JPN":"だが空間と時間、2つの軸を同時に操作することはできないから必ず決められた場所に向かうべきだったのだよ。","ENG":"However, she can't manipulate both axes of time and space simultaneously, so she had to go to a specific location.","TWN":"但又因為她無法同時操控空間和時間這兩條軸線，所以必須事先前往指定的地點。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"시간을 조종한다고…? 코핀컴퍼니에 그런 엄청난 능력자가 있다는 정보는 없었는데?","JPN":"時間を操作する……？　コフィンカンパニーにそれほどの能力者がいるって情報はなかったけど。","ENG":"Manipulate time...? This is the first time hearing of someone with such an incredible ability in Coffin Company.","TWN":"操控時間……？科芬公司裡還有這種厲害的人物？這種情報我可沒聽說過啊？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"당신이 관리국에서 요구한 고철들을 순순히 넘겨줄 때부터 이상하긴 했지만…","JPN":"管理局が要求した鉄くずをあなたが素直に渡してくれた時からおかしいとは思ったんだけど……","ENG":"But I knew something was up when you obediently handed over the scrap metal the Administration requested...","TWN":"在你願意乖乖交出管理局要求的廢鐵時，我就覺得有些奇怪了……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…역시 그 회사에 압류되지 않은 보물이 더 남아있는 건가?","JPN":"……やっぱりあの会社に差し押さえられてない宝物がまだ残ってるとか？","ENG":"...So, I'm assuming you still have treasures that weren't confiscated?","TWN":"……果然那家公司還有未被查封的人造神器嗎？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"오해는 말게. 우리 회사에서 넘겨줄 수 있는 물건은 그때 전부 넘겼어.","JPN":"誤解しないでくれたまえ。私の会社から渡せるものはあの時すべて渡した。","ENG":"Don't be mistaken. I handed over everything I could from our company that day.","TWN":"喔，為了避免誤會。我們公司當時能上繳的東西已經全部交付了。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"시간을 움직이는 <color=#ffd34c>수단</color>은 회사가 아니라 외부에서 가져온 거니까.","JPN":"時間を動く<color=#ffd34c>手段</color>は会社ではなくて外部から持ってきたものだからな。","ENG":"The <color=#ffd34c>means</color> of moving time is something from outside the company, not within.","TWN":"移動時間的<color=#ffd34c>手段</color>算是外援，並不是出自公司內部。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"외부?","JPN":"外部？","ENG":"Outside?","TWN":"外援？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"설마, 그 <color=#ffd34c>수단</color>이란 게 아케론의 죄수를 말하는 거야? 그래서 우물에 그 녀석의 흔적이 있는지 물어봤던 거고?","JPN":"まさか、その<color=#ffd34c>手段</color>ってアケロンの囚人のこと？　それで井戸にあいつの痕跡が残ってるかを聞いたわけ？","ENG":"Wait. When you say <color=#ffd34c>\\"means\\"</color>, are you referring to the Acheron prisoner? And that's why you asked if there were traces of her at the Well?","TWN":"你的意思是，那個<color=#ffd34c>手段</color>是指黃泉的囚犯？所以你才要我問井裡有沒有那傢伙的痕跡？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그렇지.","JPN":"ああ。","ENG":"Correct.","TWN":"是的沒錯。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"확인 차 물어보겠는데. 그 탈주범 패러독스가 아케론에서 사라진 게 당신 직원 짓은 아니지?","JPN":"これは確認だけど。あの脱走犯パラドックスがアケロンから消えたのって、あなたの職員の仕業じゃないよね？","ENG":"Just so we're on the same page, your employee wasn't at fault for letting Paradox disappear from Acheron, right?","TWN":"確認一下。那個叫悖論的逃犯從黃泉離開，不是你們員工幹的吧？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"부정하지 않겠네. 패러독스가 아케론에 있다는 정보를 흘린 건 나였으니까.","JPN":"否定はしないさ。パラドックスがアケロンにいるという情報を流したのは私だったからな。","ENG":"I won't deny it. I was the one who leaked the information that Paradox was in Acheron.","TWN":"我不可否認這點。因為的確是我透露了悖論的消息。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그럼 패러독스가 가진 미상의 <color=#ffd34c>재난 수준 능력</color>이라는 게 타임머신이란 것도 당신은 알고 있었단 거야?","JPN":"じゃあ、パラドックスが持っている未詳の<color=#ffd34c>災難レベルの能力</color>がタイムマシンだってこともあなたは知ってたんだ？","ENG":"So, you knew that Paradox's unknown <color=#ffd34c>disaster-level ability</color> was a time machine?","TWN":"所以，你一直都知道，悖論所擁有的未知的<color=#ffd34c>災難級能力</color>是時光機之類的東西？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"타임머신이란 별명을 붙일 정도로 편리한 능력은 아니야.","JPN":"タイムマシンというあだ名がつくほど便利な能力ではない。","ENG":"Her ability isn't convenient enough to be nicknamed a time machine.","TWN":"嚴格來講，她的能力並沒有方便到可以被稱之為時光機。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"패러독스가 갈 수 있는 과거는 극히 한정되니까.","JPN":"パラドックスが行ける過去はかなり限定的だからな。","ENG":"The past that Paradox can traverse to is extremely limited.","TWN":"悖論能回到的過去是極其有限的。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"어쨌든 시간계 간섭이 가능한 카운터라는 거잖아! 왜 그런 걸 여태 관리국은 몰랐던 거야?","JPN":"とにかく時間系の干渉ができるカウンターってことでしょう！　どうして管理局は今までそんなことを知らなかったの？","ENG":"Who cares about that. She's a Counter who can interfere with time! How did the Administration not know about that?","TWN":"不管怎麼說，她是能夠干涉時間的制裁者啊！為什麼管理局到現在都不知道這種事？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"자세한 건 잭슨의 행방을 찾은 뒤에 전부 소명하겠네.","JPN":"詳しいことはジャクソンの行方を探してから全部釈明するとしよう。","ENG":"I'll explain all the details after we find Jackson's whereabouts.","TWN":"哈哈……詳細情況我會等找到傑森的下落後再全部說明。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그때까지 협조 좀 부탁하지.","JPN":"その時まで協力を頼む。","ENG":"So please, cooperate with me until then.","TWN":"在那之前，請多多配合。"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"하…! 그러셔?","JPN":"は……！　あ、そう。","ENG":"Hah...! Oh, yeah?","TWN":"哈……？是這樣嗎！？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"그것도 <color=#ffd34c>최고</color>관리자 나으리만 알 수 있는 <color=#ffd34c>최고</color>비밀이란 거지? 그래 그래.","JPN":"それも<color=#ffd34c>最高</color>管理者さんだけが知ってる<color=#ffd34c>最高</color>秘密ってわけだね？　はいはい。","ENG":"So this is another <color=#ffd34c>super</color> secret only the <color=#ffd34c>Supreme</color> Administrator can know about? Sure, sure.","TWN":"呵呵……呵！！那個也是<color=#ffd34c>最高</color>管理者才能知道的<color=#ffd34c>最高</color>機密吧？嗯，嗯。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"나 같은 <color=#ffd34c>말단</color>관리자는 수준에 걸맞게 맡은 <color=#ffd34c>말단</color>업무나 하고 있어야겠다. 그치? 앙?","JPN":"私みたいな<color=#ffd34c>末端</color>管理者は自分の位置に相応しい<color=#ffd34c>末端</color>の業務をしてないとね。そうでしょう？　あん？","ENG":"I guess a <color=#ffd34c>grunt</color> Administrator like me should know her place and do <color=#ffd34c>grunt</color> work, is that it? Hmm?","TWN":"像我這樣的<color=#ffd34c>基層</color>管理者就應該做些符合自己身分的<color=#ffd34c>基層</color>工作。是吧？就是這樣對吧？？？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L34_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"그럼, 시니어 잭슨에 대한 단서를 찾은 뒤에 다시 연락드리겠습니다.","JPN":"では、シニア・ジャクソンについての手がかりを見つけ次第またご連絡いたします。","ENG":"Then, I'll call again once I have a clue as to where Senior Jackson is.","TWN":"那麼，我會在找到傑森的線索後再跟前輩聯絡。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"LOTUS_ADMIN_NULL_NULL","text":{"KOREA":"야, 지금 시니어님이 말씀하시는데 누구 멋대로 끊으려…!","JPN":"おい、今シニア様が話してるのになに勝手に切ろうと……！","ENG":"Hey, a Senior is talking! How dare you cut m–!","TWN":"喂，現在是前輩在說話，你竟敢掛我電話……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LOTUS_ADMIN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L37_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"흠흠…","JPN":"おほん……","ENG":"Ahem...","TWN":"呃……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L38_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그럼 다음은 그 잭슨 씨란 분을 찾으면 되는 거네요.","JPN":"じゃあ、次はそのジャクソンさんって人を探せばいいんですよね。","ENG":"So, our next agenda is finding this Jackson person?","TWN":"那接下來就是找到那個叫傑森的人了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうだな。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"사실 잭슨이 남긴 마지막 교신 좌표도 이곳에서 그리 멀지 않은 곳에 있다네.","JPN":"実はジャクソンが残した最後の交信座標もここからさほど離れていないところにある。","ENG":"The last comms coordinates Jackson left aren't far from here.","TWN":"其實傑森留下的最後通訊座標也在離這裡不遠的地方。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이미 확인해봤지만, 그곳은 텅 빈 벌판이더군.","JPN":"すでに確認してみたんだが、そこは何もないただの平原だった。","ENG":"I already checked, but it was an empty field.","TWN":"我已經確認過了，那邊是一片空曠的原野。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"네? 유일한 단서가 허탕이면 그분은 무슨 수로 찾죠?","JPN":"えっ？　唯一の手がかりがハズレたら、その人はどうやって探すんですか？","ENG":"What? How are we supposed to find him when our only clue is a dead end?","TWN":"呃？這麼說唯一的線索落空了，我們要怎麼才能找到他……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"무언가 있어야 할 곳에 아무것도 없다는 건, 이면에 숨겨진 다른 가능성을 의미합니다.","JPN":"何かがあるべきところに何もいないということは、裏に隠されている他の可能性を意味します。","ENG":"If something that is supposed to be there is not, it could mean another hidden possibility on the other side.","TWN":"如果說有東西在本該存在的地方消失了，也必定在另一面隱藏著其他的可能性。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"이면에 숨겨진 가능성…?","JPN":"裏に隠されている可能性……？","ENG":"A hidden possibility on the other side...?","TWN":"隱藏在另一面的可能性……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"설마 저희… 이면세계로 가는 건가요?","JPN":"まさか、私たち……裏世界に行くんですか？","ENG":"Wait... Are we going to the Counterside?","TWN":"難道我們……要去異界嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그래.","JPN":"ああ。","ENG":"Yes.","TWN":"是的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 이면세계에 잭슨이 있을 거란 확신은 없지만, 할 수 있는 건 전부 해봐야겠지.","JPN":"その裏世界にジャクソンがいるという確信はないが、できることはすべてやってみなくては。","ENG":"There is no certainty that Jackson is there, but we must do everything that we can.","TWN":"雖然不能確定傑森會在那在，但我們必須盡力去嘗試。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"무슨 말씀인지 이해했어요.","JPN":"どういうことか理解しました。","ENG":"I understand.","TWN":"我明白你的意思。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"하지만 무슨 수로 들어가죠? 저희한테는 차원함선도 없는데.","JPN":"でも、どうやって入るんですか？　私たちには次元艦船もないじゃないですか。","ENG":"But how? We don't even have a dimensional ship.","TWN":"但是我們怎麼進去呢？我們沒有次元艦船啊……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"가장 쉬운 방법은 합의체에게 부탁해 다이브가 가능한 함선을 빌리는 걸세.","JPN":"もっとも簡単な方法は合意体に頼み、ダイブができる艦船を借りることさ。","ENG":"The easiest method is to ask the Northern Union if we can borrow a ship that can dive.","TWN":"最簡單的方法是找北方和議會借一艘可以躍入的艦船。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"관광객이 보트를 빌리는 것처럼 말씀하셔도… 그게 될까요?","JPN":"観光客がボートを借りるような言い方をしても……それってできるんでしょうか？","ENG":"You say it like we're tourists trying to borrow a boat, but... do you think they'll say yes?","TWN":"你說得好像租遊艇一樣……行得通嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"제가 듣기에도 그 말씀은 좀 비현실적인 방안 같군요.","JPN":"私が聞いても、それは少し非現実的な方法に思います。","ENG":"Even I think this is a little unrealistic.","TWN":"我也覺得這一點有些不切實際。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"만약 빌릴 수 없다면, 그땐 좀 험한 수단을 써야겠지.","JPN":"もし借りることができないなら、その時には少し乱暴な手を使うことになるな。","ENG":"If we can't, we'll have to resort to more aggressive methods.","TWN":"嗯……如果借不到的話，那就只能鋌而走險了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"험한 수단…?","JPN":"乱暴な手……？","ENG":"Aggressive...?","TWN":"鋌而走險……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저희 약탈도 하나요?","JPN":"私たち、略奪でもするんですか？","ENG":"Are we stealing it?","TWN":"我們要去偷嗎……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"침식파 계수기를 보게나. 변동폭이 불안정하게 바뀌고 있어.","JPN":"侵食波の計測器を見たまえ。変動の幅が不安定に変化している。","ENG":"Take a look at the Corruption ray coefficient meter. The fluctuation range is becoming unstable.","TWN":"不，你看看侵蝕波係數器。波動幅度在不穩定地變化。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"이건 차원폭풍의 전조라네.","JPN":"これは次元の暴風の前兆さ。","ENG":"This is a precursor to a dimensional storm.","TWN":"這是次元風暴的前兆。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"차원… 폭풍?","JPN":"次元……嵐？","ENG":"A dimensional... storm?","TWN":"次元……風暴？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"이곳에서의 볼일은 끝나신 것 같군요.","JPN":"ここでの用事は済んだようですね。","ENG":"Your business seems to be done here.","TWN":"你在這裡的事情好像已經結束了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"저희가 안전하게 본국으로 송환해드리겠습니다.","JPN":"私たちが安全に本国まで送還いたします。","ENG":"We will repatriate you all safely back home.","TWN":"我們會安全地把你護送回國。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"미안하지만 다른 곳을 좀 더 둘러봐도 되겠나?","JPN":"すまないが、他のところをもう少し見て回ることはできないかね？","ENG":"I'm sorry, but do you mind if we go somewhere else?","TWN":"抱歉，可以再去別的地方看看嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"상부의 허가는 우물 표면을 조사하는 것까지만 유효합니다.","JPN":"上層部の許可は井戸の表面を調査するまでが有効です。","ENG":"Command has only permitted you to inspect the Well.","TWN":"上級只允許你們調查井的外圍。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"협조를 거부한다면 저희도 강제력을 동원하는 수 밖에…","JPN":"協力を拒むのであれば、私たちも強制的に……","ENG":"If you refuse to cooperate, we will have no choice but to use force–","TWN":"如果拒絕合作，我們也只能動用強制手段……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"이상하군.","JPN":"おかしいな。","ENG":"That's odd.","TWN":"奇怪了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"침식파 계수가 갑자기 이렇게 높아지다니?","JPN":"侵食波の係数がいきなりこんなに高くなるなんて。","ENG":"Why is the Corruption ray level suddenly so high?","TWN":"侵蝕波係數突然變得這麼高？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":null,"text":{"KOREA":"알린다. 그라운드 제로 중심으로부터 급성 차원폭풍의 확산을 감지.","JPN":"総員に告ぐ。グラウンド・ゼロの中心から急性次元の暴風の拡散を感知。","ENG":"Alerting all personnel. We have detected an abrupt expansion of a dimensional storm coming from the center of Ground Zero.","TWN":"通知，從G0地帶中心檢測到急性的次元風暴擴散現象。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"밸브 내부의 전 병력은 신속하게 대피해라.","JPN":"バルブ内部の全兵力は迅速に退避せよ。","ENG":"All units within the Valve are to quickly evacuate.","TWN":"閥門內部的所有兵力請迅速撤離。"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"확인했다…!","JPN":"了解した……！","ENG":"Confirmed...!","TWN":"收到……！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L32_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"들으셨습니까? 휘말리기 전에 어서 대피를…!","JPN":"聞きましたか？　巻き込まれる前に早く退避を……！","ENG":"Did you hear that? We must get out of here before–!","TWN":"聽到了嗎？我們得在被捲入風暴之前快點撤離……！"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"…사라졌어?","JPN":"……消えた？","ENG":"...They're gone?","TWN":"……人呢？"},"stage":{"bg":"SKY_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_DOLL_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L38_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"알린다! <color=#ffd34c>방문객</color>이 감시망을 벗어났다! 밸브의 출로를 모두 봉쇄해라!","JPN":"総員に告ぐ！　<color=#ffd34c>訪問者</color>が監視網から逃げた！　バルブの出路をすべて封鎖しろ！","ENG":"Alert! <color=#ffd34c>The visitors</color> have escaped our surveillance! Block all exits from the Valve!","TWN":"警報！<color=#ffd34c>訪客</color>脫離了我們的監視網！封鎖所有閥門出口！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L39_1","type":"dialog","speaker":"SOLDIER_DOLL_NPC_NULL","text":{"KOREA":"반복한다…!","JPN":"繰り返す……！","ENG":"I repeat–!","TWN":"重複一遍……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"저 사이렌 소리. 차원폭풍 때문에 울리는 건 아닌 것 같네요.","JPN":"あのサイレン音。次元の暴風のせいで鳴ってるわけじゃなさそうですね。","ENG":"That siren. I don't think it's because a dimensional storm is coming.","TWN":"剛才那個警報。好像不是因為次元風暴吧……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"저희가 사라진 걸 눈치챘을 테니, 지금쯤 균열 외부로 통하는 길이 모두 막혔을 겁니다.","JPN":"私たちが消えたことに気付いているはずですから、今頃亀裂の外に繋がる道はすべて封鎖されたでしょう。","ENG":"They must've noticed we've gone missing and will soon block off all exits leading out of the Crevice.","TWN":"他們應該已經察覺到我們消失了，現在通往峽谷外部的所有道路都被封鎖了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"도망친 것까진 좋았지만 이제 어쩌죠?","JPN":"逃げたのはいいんですけど、これからどうするんですか？","ENG":"So we successfully ran away, but what do we do now?","TWN":"所以現在逃是逃走了，但是又能怎麼辦呢……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"우선 두 분 모두 제 팔을 잡아보시겠습니까?","JPN":"まずはお二人とも私の腕を掴んでくれませんか？","ENG":"Firstly, could both of you grab my arm?","TWN":"首先，兩位能抓住我的手臂嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"잡았…","JPN":"掴みまし……","ENG":"Okay–","TWN":"好……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"우와, 단단해.","JPN":"うわ、カッチカチ。","ENG":"Whoa, it's so hard.","TWN":"哇啊，好結實。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"그 말대로군. 아주 단단한 팔뚝이야.","JPN":"そのとおりだな。とても硬い腕だ。","ENG":"Exactly. You have strong arms.","TWN":"說的對，真是可靠的臂膀啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그런데, 계속 여기에 남아있으면 그 차원폭풍이란 거에 휘말리는 거 아닌가요?","JPN":"でも、ずっとここに残ってるとあの次元の暴風ってやつに巻き込まれるんじゃないですか？","ENG":"But won't we get caught up in the dimensional storm if we stay here like this?","TWN":"但是，如果繼續留在這裡，不會被那個次元風暴捲進去嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"크리스 양은 차원폭풍에 대해 알고 있나?","JPN":"クリス君は次元の暴風について知っているのかね？","ENG":"Do you know what a dimensional storm is, Chris?","TWN":"克莉絲知道有關次元風暴的事情嗎?"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그게 뭔지 몰라서 더 무서운데요!","JPN":"それが何なのかわからないから、もっと怖いんですよ！","ENG":"No, which makes it even scarier!","TWN":"因為不知道那是什麼，所以才覺得更可怕啊……！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"말 그대로 폭풍입니다.","JPN":"言葉どおり、嵐です。","ENG":"It's literally a storm.","TWN":"就是字面意思的風暴。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"차이점이 있다면 휘말리는 순간 하늘로 날아오르는 대신, 더 깊은 심도의 이면세계로 가라앉게 되죠.","JPN":"通常の嵐との相違点は、巻き込まれる瞬間に空に飛びあがるのではなく、深い深度の裏世界に沈むということでしょう。","ENG":"The only difference is that instead of getting flung into the sky, you sink into the deep depths of the Counterside.","TWN":"如果有區別的話，就是在被捲入的瞬間，不會被拋飛到天空，而是捲入更深層的異界。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"아하, 이면세계로 가라앉는…","JPN":"へえ、裏世界に沈む……","ENG":"A-ha! So, you sink into the Countersi–","TWN":"啊哈，捲入異界……"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"에…?","JPN":"え……？","ENG":"What...?","TWN":"呃……？"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"설마 아까 말한 거친 수단이라는 게…","JPN":"まさか、さっき話した乱暴な手って……","ENG":"The aggressive method you mentioned before...","TWN":"這就是你說的鋌而走險嗎……"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"차원폭풍에 뛰어드는 건 아니죠?","JPN":"次元の暴風に飛び込むってことじゃないですよね？","ENG":"Was it jumping into the dimensional storm?","TWN":"該不會是要跳進次元暴風吧？！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"S급 카운터인 파티마 양의 CRF는 침식파 뿐만 아니라 차원폭풍 속에서도 내성을 갖는다네.","JPN":"S級カウンターであるファティマ君のCRFは侵食波だけでなく、次元の暴風の中でも耐性を持つ。","ENG":"Fatima is a Grade S Counter whose CRF is resistant to not only Corruption rays, but also dimensional storms.","TWN":"法蒂瑪是S級制裁者，她的CRF不僅對侵蝕波有抗性，在次元風暴中也能保持相對的穩定。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"북방군의 감시를 따돌리면서 목적지로 향하는 일석이조의 기회를 놓칠 수는 없지.","JPN":"北方軍の監視をかわして目的地に向かう一石二鳥のチャンスを逃すわけにはいかない。","ENG":"This is our chance to both hide from the Northern Union and head to our destination. Killing two birds with one stone, as they say.","TWN":"這是我們甩開北方和議會監視前往目的地的好機會。如此一來便是一舉兩得了。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"그 기회…! 안전한 거 맞나요?!","JPN":"そのチャンス……！　本当に安全なんですか！？","ENG":"And this chance...! Is it safe?!","TWN":"是機會沒錯……但是……！這真的安全嗎？！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_HATE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"물론 위험하지.","JPN":"もちろん危険さ。","ENG":"Of course, not. It's dangerous.","TWN":"當然不安全。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"차원미아가 되고 싶지 않다면, 파티마 양의 팔을 놓치지 말게나.","JPN":"次元迷子になりたくないなら、ファティマ君の腕から手を放さないように。","ENG":"So, if you don't want to become dimension-lost, you'd better hold on tight to Fatima's arm.","TWN":"如果不想迷失在次元裡，就不要放開法蒂瑪的手臂。"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"FATIMA_LOTUS_NULL_NULL","text":{"KOREA":"차원폭풍이 옵니다! 모두 꽉 잡으십시오!","JPN":"次元の暴風が来ます！　しっかり掴まってください！","ENG":"The dimensional storm is coming! Hold on tight, everyone!","TWN":"風暴來了！請大家抓緊！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_WIND"},{"id":"L23_1","type":"dialog","speaker":"ROOKIE_GRONIA_NULL_NULL","text":{"KOREA":"으아아…! 이럴 줄 알았으면 어제 편의점 말고 뷔페라도 다녀올 걸!!","JPN":"わああ……！　こんなことだったら昨日はコンビニご飯じゃなくてビュッフェに行けばよかった！！","ENG":"AAAAGH...! I should've gone to a buffet instead of getting food at the convenience store if I knew this was going to happen to me!!","TWN":"啊啊啊……！早知道會這樣，昨天就不去便利店了，應該去吃到飽餐廳的！！"},"stage":{"bg":"SKY_NIGHT","bgm":"BATTLE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FATIMA_LOTUS_NULL_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ROOKIE_GRONIA_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};